import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance with default config
const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json'
  }
});

// Add auth token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  // Add language to all requests
  const language = localStorage.getItem('selectedLanguage') || 'english';
  config.headers['X-Language'] = language;

  return config;
});

export default api;

/**
 * Language-aware API endpoints
 */

// Chapters API - automatically filters by current language
export const chaptersAPI = {
  // Get all chapters for current language
  getAll: () => {
    const language = localStorage.getItem('selectedLanguage') || 'english';
    return api.get(`/chapters?language=${language}`);
  },

  // Get specific chapter
  getChapter: (chapterId) => api.get(`/chapters/${chapterId}`),

  // Get lesson within chapter
  getLesson: (chapterId, lessonId) => 
    api.get(`/chapters/${chapterId}/lessons/${lessonId}`),

  // Admin: Create chapter for specific language
  create: (language, chapterData) => 
    api.post(`/admin/chapters?language=${language}`, chapterData),

  // Admin: Update chapter
  update: (chapterId, chapterData) => 
    api.put(`/admin/chapters/${chapterId}`, chapterData),

  // Admin: Delete chapter
  delete: (chapterId) => api.delete(`/admin/chapters/${chapterId}`)
};

// Practice Sessions API - automatically filters by current language
export const practiceAPI = {
  // Get all practice sessions for current language
  getAll: () => {
    const language = localStorage.getItem('selectedLanguage') || 'english';
    return api.get(`/practice?language=${language}`);
  },

  // Get specific practice session
  getSession: (sessionNumber) => api.get(`/practice/${sessionNumber}`),

  // Admin: Create practice session for specific language
  create: (language, sessionData) => 
    api.post(`/admin/practice?language=${language}`, sessionData),

  // Admin: Update practice session
  update: (sessionNumber, sessionData) => 
    api.put(`/admin/practice/${sessionNumber}`, sessionData),

  // Admin: Delete practice session
  delete: (sessionNumber) => api.delete(`/admin/practice/${sessionNumber}`)
};

// Progress API - tracks progress per language
export const progressAPI = {
  // Get lesson progress for current language
  getLessonProgress: () => {
    const language = localStorage.getItem('selectedLanguage') || 'english';
    return api.get(`/progress/lessons?language=${language}`);
  },

  // Submit lesson completion
  submitLesson: (lessonData) => api.post('/progress/lessons', lessonData),

  // Get practice progress for current language
  getPracticeProgress: () => {
    const language = localStorage.getItem('selectedLanguage') || 'english';
    return api.get(`/progress/practice?language=${language}`);
  },

  // Submit practice session completion
  submitPractice: (practiceData) => api.post('/progress/practice', practiceData)
};

// User API
export const userAPI = {
  getProfile: () => api.get('/users/profile'),
  updateProfile: (data) => api.put('/users/profile', data)
};
